SELECT reference, current_use, year_built, p.area_m2
FROM catastro.edificios e JOIN catastro.parcelas p USING(reference)
WHERE ST_Contains(e.geom, ST_Point(-3.6746686,40.4250675));

SELECT 'ruido' tipo, min(ST_Distance(geom, pt)) d FROM od.contaminacion_acustica_estaciones_de_medida
UNION ALL SELECT 'trafico', min(ST_Distance(geom, pt)) FROM od.aforos_de_trafico_permanentes
UNION ALL SELECT 'aire',    min(ST_Distance(geom, pt)) FROM od.calidad_del_aire_estaciones_de_control;
